import subprocess
from pathlib import Path

import pytest

AC_UID = "3619ae6db161fb50"
AC_TYPE = "hook"

REPO_ROOT = Path(__file__).resolve().parents[3]
TARGETS = [
    "agent-scores.json",
    "agent-scores.json.lock",
    ".claude/specs/spec-20260518-225715/",
]


def test_AC_07():
    """
    GIVEN: dev has removed the three targets from the git index while preserving working-tree files via `git rm -r --cached -- agent-scores.json agent-scores.json.lock .claude/specs/spec-20260518-225715/`. Equivalent index operations are acceptable — AC verifies end state.
    WHEN:  (a) `git ls-files agent-scores.json agent-scores.json.lock .claude/specs/spec-20260518-225715/` is run; (b) for each path P enumerated by `git ls-tree -r HEAD --name-only -- <targets>`, working-tree path P is queried for EXISTENCE only
    THEN:  stdout from (a) is empty AND exit 0; for every path P enumerated by (b), the working-tree copy MUST still exist — proving `--cached` preserved presence. Content equality NOT asserted (OBJ-11 fix: cp-state-qa.json and agent-scores.json are mutable runtime telemetry).
    """
    # (a) git ls-files must return empty stdout + exit 0
    proc = subprocess.run(
        ["git", "ls-files", "--"] + TARGETS,
        cwd=str(REPO_ROOT),
        capture_output=True,
        text=True,
        check=False,
    )
    assert proc.returncode == 0, (
        f"git ls-files non-zero exit ({proc.returncode}); stderr={proc.stderr!r}"
    )
    assert proc.stdout == "", (
        f"git ls-files must return empty stdout (targets still tracked): {proc.stdout!r}"
    )

    # (b) for each path under HEAD that matches a target prefix, working-tree path must exist.
    head_tree = subprocess.run(
        ["git", "ls-tree", "-r", "HEAD", "--name-only", "--"] + TARGETS,
        cwd=str(REPO_ROOT),
        capture_output=True,
        text=True,
        check=False,
    )
    # ls-tree exit 0 even with empty stdout (no historical tracking); only fail on git error.
    assert head_tree.returncode == 0, (
        f"git ls-tree non-zero exit ({head_tree.returncode}); stderr={head_tree.stderr!r}"
    )
    missing = []
    for line in head_tree.stdout.splitlines():
        line = line.strip()
        if not line:
            continue
        p = REPO_ROOT / line
        if not p.exists():
            missing.append(line)
    assert not missing, (
        f"working-tree copies missing for previously-tracked paths (--cached should preserve): {missing}"
    )
